"use client";

import { useEffect, useState } from "react";

/**
 * Apple-"hello"-style handwriting intro. Reveals the owner's real "Peaches
 * Lounge" wordmark (vector-traced from the brand logo via potrace) through an
 * animated SVG mask that sweeps a thick round-capped stroke along the
 * wordmark's handwriting centerline, then the whole overlay lifts away. Plays
 * once per browser-tab session and is fully skipped for anyone who prefers
 * reduced motion.
 *
 * The letterforms themselves (LOGO_TRANSFORM + LOGO_PATHS, traced from
 * public/brand/logo-traced.svg) are static and always fully drawn — what
 * animates is a <mask> whose stroke widens/travels along CENTERLINE_D
 * (traced by hand along the wordmark's writing centerline) using
 * stroke-dasharray/dashoffset with pathLength={1} for browser-independent
 * normalization. Keyframes + colors live in globals.css (`.pl-splash*`) and
 * follow the same --pl-splash-bg/--pl-splash-ink theme variables as the rest
 * of the app.
 */
const SESSION_KEY = "pl-splash-seen";

// Default draw duration in seconds — matches the original hardcoded
// `pl-draw 2.4s` timing exactly when no `duration` prop is passed.
const DEFAULT_DRAW_SECONDS = 2.4;

// potrace group transform from public/brand/logo-traced.svg, preserved
// exactly (flips the y axis potrace traces in) so the inlined paths below
// line up with the mask's viewBox coordinates.
const LOGO_TRANSFORM = "translate(-190.058945,1022.930872) scale(0.100000,-0.100000)";

// The three potrace-traced letterform paths from public/brand/logo-traced.svg
